#!/usr/bin/env bash
# Generated by Agent: IMPLEMENT | Feature: EVOL-011
# ============================================================================
# release-concurrency-lock.sh — Stop hook: release per-branch session lock
# ============================================================================
# Runs at end of every Claude Code turn (Stop event).
# Removes .context/locks/{branch}.lock if it belongs to this session.
# ============================================================================

set -uo pipefail

REPO_ROOT=$(git rev-parse --show-toplevel 2>/dev/null || echo '')
if [ -z "$REPO_ROOT" ]; then
  exit 0
fi

BRANCH=$(git branch --show-current 2>/dev/null || echo '')
if [ -z "$BRANCH" ]; then
  exit 0
fi

SAFE_BRANCH=$(echo "$BRANCH" | tr '/' '-' | tr -cd '[:alnum:]-_.')
LOCK_FILE="$REPO_ROOT/.context/locks/${SAFE_BRANCH}.lock"

if [ ! -f "$LOCK_FILE" ]; then
  exit 0
fi

SESSION_PID=${PPID:-$$}
LOCK_PID=$(head -1 "$LOCK_FILE" 2>/dev/null || echo '')

# Only remove lock if it belongs to this session
if [ "$LOCK_PID" = "$SESSION_PID" ]; then
  rm -f "$LOCK_FILE"
fi

exit 0
